public fun validate(validation: SingletonRaise<None>.(A) -> Unit): Option<A> = when (this) {
  is None -> this
  is Some -> arrow.core.raise.fold({ validation(SingletonRaise(this), value) }, { None }, { this })
}

public inline fun <reified B> Option<*>.filterIsInstance(): Option<B> =
  flatMap {
    when (it) {
      is B -> Some(it)
      else -> None
    }
  }

public inline fun <Error, A> either(block: Raise<Error>.() -> A): Either<Error, A> {
  contract { callsInPlace(block, InvocationKind.AT_MOST_ONCE) }
  return fold(block, { Either.Left(it) }, { Either.Right(it) })
}

data class OfTypeMatcher<in T : Any>(
    val cls: KClass<*>,
) : Matcher<T> {
    override fun match(arg: T?): Boolean = cls.isInstance(arg)

    override fun toString() = "ofType(${cls.simpleName})"
}

open fun <T> elementAt(i: Int, clazz: KClass<*>): T =
        if (i < _values.size) {
            _values[i] as T
        } else {
            throw NoParameterFoundException(
                "Can't get injected parameter #$i from $this for type '${clazz.getFullName()}'",
            )
        }

